/* 手机底部广告弹窗 - HTML/CSS 原型 */
.phone-popup-container {
  position: relative;
  width: 100%;
  height: 100vh;
  max-width: 375px;
  margin: 0 auto;
  overflow: hidden;
  background-color: #ffffff;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.phone-popup-bg {
  position: absolute;
  inset: 0;
  background-image: url('/data/proj_1779608460372/assets/images/c64b75dd5d0cc1f967a4ccc6.png');
  background-size: cover;
  background-position: center;
}

.phone-popup-overlay {
  position: absolute;
  inset: 0;
  background-color: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: flex-end;
  justify-content: center;
}

.phone-popup-content {
  width: 100%;
  display: flex;
  flex-direction: column;
}

.phone-popup-image {
  width: 100%;
  display: block;
  object-fit: cover;
}

.phone-popup-actions {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 20px;
  padding: 8px 16px 20px;
  background-color: #ffffff;
}

.phone-popup-button {
  display: flex;
  justify-content: center;
  align-items: center;
  width: 280px;
  height: 44px;
  border-radius: 30px;
  background-color: #fcda00;
  color: #544300;
  text-align: center;
  font-size: 18px;
  font-weight: 500;
  line-height: 150%;
  font-family: "PingFang SC", sans-serif;
  cursor: pointer;
}

.phone-popup-secondary {
  color: #666666;
  text-align: center;
  font-size: 18px;
  font-weight: 400;
  line-height: 150%;
  font-family: "PingFang SC", sans-serif;
  cursor: pointer;
}

/* 平板居中广告弹窗 - HTML/CSS 原型 */
.pad-popup-container {
  position: relative;
  width: 100%;
  height: 100vh;
  max-width: 1024px;
